PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX p: <http://www.wikidata.org/prop/>
PREFIX pr: <http://www.wikidata.org/prop/reference/>

SELECT DISTINCT ?person ?spouse ?occupation
WHERE {
  {
    ?person wdt:P166 wd:Q1191573.
  } UNION {
    ?person wdt:P166 wd:Q1191574.
  }
  ?person p:P166 ?statement.
  ?statement pr:P854 ?ceremony.
  ?ceremony wdt:P585 ?ceremonyDate.
  FILTER (year(?ceremonyDate) >= 2019)
  ?person wdt:P26 ?spouse.
  ?spouse wdt:P106 ?occupation.
}

